var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"오느라 고생했다, 레이. 여기가 센트럴 팰리스야.","JPN":"お疲れ様、レイ。ここがセントラルパレスだ。","ENG":"I hope that the trip here wasn’t too difficult for you, Ray. This is Central Palace.","TWN":"路上辛苦了，雷伊，這裡就是聖特羅貝里斯。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"우와…….","JPN":"うわぁ……","ENG":"Whoa...","TWN":"哇……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"여관에 묵던 여행자들에게 들을 때는 반쯤 허풍인 줄 알았는데……. 듣던 것보다 엄청나.","JPN":"旅館に泊まっていた旅の人に聞いた時は、話半分と思っていたけど……聞いていたのより凄いね。","ENG":"I thought that the stories told by the travelers staying at the inn were greatly exaggerated... But this is way more impressive than what I’ve heard.","TWN":"我聽那些住在旅館的旅客們在描述時，還以為他們在吹牛呢……沒想到比我聽到的還誇張。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"평소보다 북적거리는 편이야. 내일이 구원 기사단의 출정식이기 때문이지.","JPN":"いつもよりごった返している方だ。明日、救世騎士団の出征式があるからな。","ENG":"It’s more crowded than it usually is. That’s because the Knights of Redemption are holding their ceremony of war tomorrow.","TWN":"平時沒這麼熱鬧的，是因為明天要舉行救贖騎士團的出征儀式。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"출정식은 구원자와 성녀를 선출하는 자리다. 구경꾼들이 몰릴 수밖에.","JPN":"出征式は救世主と聖女を選ぶ場だ。見物客が押し寄せないはずがない。","ENG":"The Savior and Saintess will be selected during the ceremony. Of course there will be spectators.","TWN":"在出征儀式中會選出救贖者和聖女，因此大家都會聚集到這裡來觀禮。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"구원 기사단이면……. 알렌이랑 버밍엄 부인이 속해 있다던 곳 말이지?","JPN":"救世騎士団といえば……アレンとバーミンガム夫人が所属しているところでしょ？","ENG":"The Knights of Redemption... Aren’t you and Lady Birmingham part of that Order?","TWN":"救贖騎士團……就是你和伯明罕夫人所屬的組織吧？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"미리 말해두는데 그레이스 앞에서 버밍엄 부인이라고는 부르지 마라.","JPN":"あらかじめ言っておくが、グレースの前ではバーミンガム夫人と呼ぶなよ。","ENG":"Just so you know, don’t call Grace \\"Lady Birmingham\\" in front of her.","TWN":"我先提醒你，在葛瑞絲面前，不要叫她伯明罕夫人。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"나이 들어 보이는 이름이라고 화를 낼 테니까.","JPN":"年取って見える名前だと怒るはずだからな。","ENG":"She’ll get mad, saying that it makes her sound old.","TWN":"她覺得這個稱呼聽起來很老，要是這樣叫她，她會生氣的。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그럼 다녀오도록 하지. 길이 험해서 피곤했을 테니 잠시 쉬고 있어.","JPN":"では、行ってくる。道が悪かったから疲れただろう。少し休んでいなさい。","ENG":"Now, I have somewhere to drop by first. You must be exhausted from the rough trip, so why don’t you take a break?","TWN":"那我先去忙，這一路上長途跋涉，你應該也累了，就先去休息吧。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"응? 알렌, 어디 가려고?","JPN":"え？　アレン、どこに行くの？","ENG":"Huh? Allen, where are you going?","TWN":"嗯？艾倫，你要去哪裡？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"네가 황태자 전하를 알현하려면 몇 가지 절차를 거쳐야 해.","JPN":"君が皇太子殿下に謁見するためには、いくつかの手順を踏まなければならない。","ENG":"I must go through a few procedures in order to seek an audience with the Crown Prince His Majesty.","TWN":"在你去見皇太子殿下之前，還需要辦一些流程。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"전하께서 사소한 일에 신경 쓰는 분은 아니지만, 뭐든 정식 절차를 거쳐야 문제가 생기지 않는 법이다.","JPN":"殿下はささいなことに気を使う方ではないが、何でも正式な手順を踏めば問題が起きないものだ。","ENG":"Although he does not trouble himself with trivial matters, it’s better to go through the official procedures and avoid any trouble.","TWN":"雖然殿下是不拘小節的人，但為免發生什麼問題，還是走正式流程比較保險。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"그렇구나…….","JPN":"そうなんだね……","ENG":"I see...","TWN":"喔喔……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"어째 갑자기 들뜬 표정이군.","JPN":"なんだか急にそわそわした顔をしているな。","ENG":"You suddenly seem excited for some reason.","TWN":"臉色怎麼突然不太對勁？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"알렌이 항상 이야기하던 황태자 전하를 직접 뵙는 거잖아. 어떤 분일지 조금은 기대돼.","JPN":"アレンがいつも話していた皇太子殿下にじかにお会いするんでしょ。どんな方なのかちょっと楽しみだ。","ENG":"Well, it’s my first time seeing the Crown Prince you always talk about in person. I’m looking forward to seeing what kind of person he is.","TWN":"我終於要親眼見到你常提到的皇太子殿下，有點期待殿下是什麼樣的人呢。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"다른 사람들 앞에서는 그렇게 말하지 마라. 불경죄로 처벌 받을 수도 있어.","JPN":"他の人の前ではそんな風に言うなよ。不敬罪で罰せられることもある。","ENG":"Don’t say that in front of other people. You may be punished for disrespecting the crown.","TWN":"在其他人面前千萬不能說這種話，很可能會被冠上大逆不道的罪名而受罰。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"내, 내가 무슨 나쁜 말이라도 했어?","JPN":"ぼ、僕、何か悪い事でも言った？","ENG":"D-did I say something wrong?","TWN":"我…我剛有說什麼不尊敬的話嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"아니, 하지만 황실 예법이라는 건 원래 엄격한 거야.","JPN":"いや、でも皇室の礼法というものは元々厳格なんだ。","ENG":"No, but imperial etiquette tends to be strict.","TWN":"沒有，只是皇室禮法本來就很嚴格。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"괜한 시비에 휘말리기 싫으면 미리 조심하는 법을 배우는 게 좋아.","JPN":"余計な言いがかりに振り回されたくなければ、事前に注意する方法を学んでおくことだ。","ENG":"It is best to learn to be cautious if you want to avoid unnecessary conflicts.","TWN":"若不想無故惹禍上身，還是學習謹言慎行比較好。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"하아……. 센트럴 팰리스는 복잡하네. 갑자기 자신이 없어졌어.","JPN":"はあ……セントラルパレスは複雑だね。急に自信が無くなったよ。","ENG":"Ha... Central Palace is so complicated. I suddenly lost all confidence.","TWN":"哀……聖特羅貝里斯真是複雜，我突然沒信心了。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"새삼스럽군. 도시 생활은 원래부터 자신 없었잖아.","JPN":"いまさらだな。都市の生活は元々自信無かったんだろう？","ENG":"Don’t act surprised. You never felt confident about city life in the first place.","TWN":"別介意，都市生活本來就不容易。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그래도 고맙다, 레이. 힘든 결정이었을 텐데 함께해 줘서.","JPN":"それでも、ありがとう、レイ。簡単ではなかったろうに、共にすると決意してくれて。","ENG":"Still, thank you, Ray. It must’ve been a difficult decision for you, but you chose to stand with us.","TWN":"不過還是很謝謝你，願意和我們一起並肩作戰，相信這不是個容易的決定。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"아냐. 나 같은 게 실제로 도움이 될 수 있을지도 잘 모르겠고.","JPN":"ううん。僕みたいなのが実際役に立つかもよくわからないし。","ENG":"No need to thank me. I’m not even sure if someone like me will actually be of any help.","TWN":"別這麼說，也不知道我是否真的能幫上忙。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"전하를 뵙자마자 쫓겨날지도 모르잖아.","JPN":"殿下にお会いするや否や、追い出されるかもしれないでしょ。","ENG":"I may be kicked out as soon as I meet His Majesty.","TWN":"說不定我一見到殿下就會被趕出去呢。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그런 일이라면 걱정하지 마라. 전하의 안목은 매우 뛰어나시다.","JPN":"そんなことなら、心配いらない。殿下のお目は確かだ。","ENG":"That’s an unnecessary concern. His Majesty has a discerning eye.","TWN":"這你倒不用擔心，殿下非常有識人的眼光，"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"분명 네 잠재력을 알아봐 주실 거야.","JPN":"きっとレイの潜在力を見抜いてくださるはずだ。","ENG":"He’ll surely recognize your potential.","TWN":"一定會看出你的潛力的。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"시간을 조금 지체했군. 서둘러야겠어.","JPN":"少し遅れてしまった。急がなければ。","ENG":"I should get going. I’ve wasted too much time as it is.","TWN":"我有點來不及了，要加緊腳步。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"저 앞 음식점에서 식사라도 하고 있어라. 오래 걸리지는 않을 거다.","JPN":"あそこの食堂で食事でもしていなさい。長くはかからないはずだ。","ENG":"Have a meal at the restaurant over there. This shouldn’t take long.","TWN":"你就先在前面的餐館吃個飯，我很快就回來。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"알겠어, 빨리 다녀와야 해.","JPN":"わかった。早く帰ってきてね。","ENG":"Okay, don’t take too long.","TWN":"好，那你快點回來。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"……예전보다 잔소리가 더 심해진 것 같네.","JPN":"……前よりも小言が酷くなったみたいだ。","ENG":"...His nagging seems to be getting worse.","TWN":"……艾倫感覺比以前更多話呢？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"역시 결혼을 해서 그런 걸까.","JPN":"やっぱり結婚するとそうなのかな。","ENG":"Maybe it’s because he got married?","TWN":"是因為結婚的關係嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"그나저나 내가 아는 메뉴가 있으려나……?","JPN":"それより、僕が知っているメニューがあるんだろうか……？","ENG":"Anyway, I wonder if there will be anything on the menu that I know...?","TWN":"不過我有看得懂的菜單嗎……？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"으음, 오는 길에 알렌이 주문했던 건 전부 처음 보는 음식뿐이었는데…….","JPN":"ううむ、来る途中でアレンが注文していたのは、全部初めて見る食べ物だったけど……","ENG":"Hmm... All of the food that Allen ordered on the way here were new to me...","TWN":"呃，來的路上艾倫點的餐點都是我沒見過的……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"저쪽으로 간다! 절대 놓치지 마!","JPN":"あっちに行ったぞ！　絶対に逃すな！","ENG":"Over there! Do not let her escape!","TWN":"往那裡跑了！別讓她溜走！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"비쩍 마른 게 잽싸기는……! 아무나 저 계집애를 잡아!","JPN":"痩せてるくせにすばしっこいやつめ……！　誰でもいい、あの小娘を捕らえろ！","ENG":"That skinny brat is faster than she looks...! Someone grab her!","TWN":"那個黃毛丫頭……！一定要給我逮到她！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"왜 저렇게 소란스럽지……? 용병들끼리 시비라도 붙었나?","JPN":"なんであんなに騒がしいんだ……？　傭兵同士で喧嘩でもしてるのかな？","ENG":"What’s with the commotion...? Did a fight break out between mercenaries?","TWN":"怎麼那麼吵……？是有傭兵在惹事嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"으윽……! 왜 안 비키고 멀뚱멀뚱 서 있는 거야……?!","JPN":"ううっ……！　なにぼけっと突っ立っているのよ……！？","ENG":"Nngh...! Why are you just standing there looking like a cow?!","TWN":"呃呃……！好狗不擋路，你杵在這幹嘛啦……？！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"아, 미, 미안. 부딪쳐 버렸네.","JPN":"あ、ご、ごめん。ぶつかっちゃったね。","ENG":"Oh, s-sorry. I didn’t mean to bump into you like that.","TWN":"啊，對…對不起，不小心撞到你。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"괜찮아? 일으켜 세워 줄까?","JPN":"大丈夫？　起きるの手伝おうか？","ENG":"Are you okay? Do you need help getting back up?","TWN":"你沒事吧？要我扶你起來嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"찾았다! 다들 포위해!","JPN":"見つけた！　包囲しろ！","ENG":"I found her! Everybody surrounds her!","TWN":"找到了！給我圍起來！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"용병이 아니라 기사 분들이시잖아……?","JPN":"傭兵じゃなくて、騎士の人たちじゃないか……？","ENG":"Wait, those are knights and not mercenaries...","TWN":"他們不是傭兵，是騎士團的……？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_SURPRISE"},"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"어떻게 된 거야, 너? 혹시 도둑질이라도 한 거야?","JPN":"どういうこと？　君、もしかして泥棒でもしたの？","ENG":"Hey, what’s going on? Did you steal something?","TWN":"他們為什麼要抓你？你偷東西嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_SURPRISE"},"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_DESPAIR"},"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"가, 가까이 오지 마! 한 발짝만 더 다가오면 얘를 죽일 거야!","JPN":"ち、近づくな！　一歩でも近づいたらこいつを殺す！","ENG":"D-don’t come any closer! Take one more step and I’ll kill him!","TWN":"別…別過來！敢再靠近一步我就殺了他！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SURPRISE"},"R":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"저……. 저기, 있잖아. 칼끝이 목에 닿아서 불편한데…….","JPN":"あ……あのさ、ほら。ナイフが首にあたってるんだけど……","ENG":"Y-you know, it’s a bit uncomfortable with your knife so close to my neck...","TWN":"　　"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_DESPAIR"},"R":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"KNIGHT_NPC_B_NULL","text":{"KOREA":"인질로 교섭을 하고 싶은 모양이군요. 어떻게 하시겠습니까?","JPN":"人質で交渉するつもりのようです。どうしますか？","ENG":"It seems that she wants to negotiate using a hostage. What would you like us to do, sir?","TWN":"她似乎是想利用人質來談判，怎麼辦？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_A_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_B_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"저 소년, 귀족인가?","JPN":"あの少年、貴族か？","ENG":"The boy, is he a noble?","TWN":"那男孩是貴族嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_A_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_B_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"KNIGHT_NPC_A_NULL","text":{"KOREA":"열람 마법으로 대조한 결과, 일치하는 인물은 없었습니다.","JPN":"閲覧魔法で照会した結果、一致する人物はいませんでした。","ENG":"Based on the results of my scanning spell, nobody matches his description.","TWN":"經由瀏覽魔法比對後，沒有發現符合的人選。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_A_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_B_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"그렇다면 저 노예 계집애와 한 패일 수도 있다는 뜻이군.","JPN":"だったら、あの奴隷の小娘の仲間かもしれないな。","ENG":"Then that means that he could be working with that slave brat.","TWN":"也就是說，他和那個奴隸丫頭也有可能是一夥的。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_A_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_B_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"둘 다 굳이 살려 둘 필요 없다! 죽여서라도 반드시 도난품을 회수하도록!","JPN":"二人とも生かしておく必要はない！　殺してもかまわん、必ず盗難品を回収しろ！","ENG":"There’s no need to keep both of them alive! Retrieve the stolen item, even if it means killing them both!","TWN":"那就兩個都不需要留活口！就算殺了他們也要把東西拿回來！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_A_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_B_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"치잇……. 인질극도 안 먹히다니, 정말 쓸모 없는 꼬맹이잖아?","JPN":"チッ……人質ごっこも効かないなんて、本当に使えないガキね？","ENG":"Tch... Not even holding you hostage works... You really are useless, aren’t you?","TWN":"嘖……竟然不吃人質這套，你真沒用！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_DESPAIR"},"R":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"저……. 아까도 말했지만 이 칼 좀 치워 주면 안 될까?","JPN":"あの……さっきも言ったけど、このナイフどけてくれない？","ENG":"Um... As I requested earlier, could you put your knife away please?","TWN":"那個……我剛也說了，可以麻煩你把刀挪開嗎？"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"},"R":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":"아무래도 내가 괜한 오해에 휘말린 것 같거든.","JPN":"どう見ても僕が余計な誤解に巻き込まれちゃったみたいだからさ。","ENG":"I think I may have been caught up in a unnecessary misunderstanding.","TWN":"我好像是無端捲入了你們的紛爭當中。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"},"R":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"시, 시끄럽네, 진짜! 저놈들에게는 너나 나나 마찬가지야!","JPN":"う、うるさいわね、もう！　あいつらにとってはあんたも私も似たようなものなの！","ENG":"S-shut up, will you?! To those bastards, there’s no difference between me and you!","TWN":"住嘴！吵死了！他們認為我們是一夥的！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"},"R":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"GRIL_KNIGHT_PAST_STAFF","text":{"KOREA":"허리에 찬 칼은 장식이야?! 죽기 싫으면 뭐든 해 봐!","JPN":"腰に下げてる剣はお飾り！？　死ぬのが嫌ならなんとかしてみなさいよ！","ENG":"Is that sword you carry around a decoration?! Do something if you don’t want to die!","TWN":"你以為他們腰間佩戴的刀只是好看的嗎？！不想死的話就快想點辦法！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"},"R":{"char_id":"GRIL_KNIGHT_PAST_STAFF","face":"UNIT_IDLE"}}}}]`);export{e as default};